import jakarta.inject.Singleton

@Singleton 
class NoRetry : RetryPolicy {

    suspend fun <I, O> execute(context: StepContext<I, O>, executable: suspend (StepContext<I, O>) -> Unit){
        executable(context)
    }
}

@Factory
class ExecutorFactory {

    @Singleton 
    fun simpleExecutor(retryPolicy: RetryPolicy): Executor { 
        return SimpleExecutor(retryPolicy)
    }
}

class EcommercePurchase(private val retryPolicy: RetryPolicy) { 

    @Scenario
    fun fromLoginToCheckout(executor: Executor) {  
        scenario("login-select-and-checkout"){
            retryPolicy(retryPolicy)
        }
        // ...
    }
}

